import{n as e,o as t,r as n}from"./app---rYyY5a.js";import{t as r}from"./plugin-vue_export-helper-BDNMzG2s.js";var i=JSON.parse(`{"path":"/posts/%E4%BA%A7%E5%93%81%E4%B8%8E%E5%8D%8F%E4%BD%9C/%E6%8A%80%E6%9C%AF%E9%80%89%E5%9E%8B%E6%96%B9%E6%B3%95%E8%AE%BA.html","title":"技术选型方法论","lang":"zh-CN","frontmatter":{"title":"技术选型方法论","tag":["技术选型","产品思维","方法论"],"category":"产品与协作","date":"2026-06-06T00:00:00.000Z","description":"技术选型方法论 技术选型方法论是连接用户需求和技术实现的桥梁，它决定了产品的价值和用户体验。 本文介绍了技术选型方法论的方法论和实践经验，帮助你提升产品思维。 技术选型失败的原因，80%不是技术本身不好，而是在错误的问题上用了正确的技术，或者在错误的时间做了正确的选择。 所以方法论的第一步不是教你怎么比较选项，是教你怎么确保自己在回答正确的问题。 一、...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"技术选型方法论\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2026-06-06T00:00:00.000Z\\",\\"dateModified\\":\\"2026-06-29T08:25:12.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"郑天祺\\",\\"url\\":\\"https://zhengtianqi.github.io\\"}]}"],["meta",{"property":"og:url","content":"https://zhengtianqi.github.io/posts/%E4%BA%A7%E5%93%81%E4%B8%8E%E5%8D%8F%E4%BD%9C/%E6%8A%80%E6%9C%AF%E9%80%89%E5%9E%8B%E6%96%B9%E6%B3%95%E8%AE%BA.html"}],["meta",{"property":"og:site_name","content":"郑天祺的博客"}],["meta",{"property":"og:title","content":"技术选型方法论"}],["meta",{"property":"og:description","content":"技术选型方法论 技术选型方法论是连接用户需求和技术实现的桥梁，它决定了产品的价值和用户体验。 本文介绍了技术选型方法论的方法论和实践经验，帮助你提升产品思维。 技术选型失败的原因，80%不是技术本身不好，而是在错误的问题上用了正确的技术，或者在错误的时间做了正确的选择。 所以方法论的第一步不是教你怎么比较选项，是教你怎么确保自己在回答正确的问题。 一、..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-29T08:25:12.000Z"}],["meta",{"property":"article:tag","content":"方法论"}],["meta",{"property":"article:tag","content":"产品思维"}],["meta",{"property":"article:tag","content":"技术选型"}],["meta",{"property":"article:published_time","content":"2026-06-06T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-29T08:25:12.000Z"}]]},"git":{"createdTime":1780732365000,"updatedTime":1782721512000,"contributors":[{"name":"zhengtianqi","username":"zhengtianqi","email":"zhengtq@bjcrg.com","commits":8,"url":"https://github.com/zhengtianqi"}]},"readingTime":{"minutes":21.26,"words":6379},"filePathRelative":"posts/产品与协作/技术选型方法论.md","excerpt":"\\n<blockquote>\\n<p>技术选型方法论是连接用户需求和技术实现的桥梁，它决定了产品的价值和用户体验。<br>\\n本文介绍了技术选型方法论的方法论和实践经验，帮助你提升产品思维。</p>\\n</blockquote>\\n<p>技术选型失败的原因，80%不是技术本身不好，而是<strong>在错误的问题上用了正确的技术</strong>，或者<strong>在错误的时间做了正确的选择</strong>。</p>\\n<p>所以方法论的第一步不是教你怎么比较选项，是教你怎么<strong>确保自己在回答正确的问题</strong>。</p>\\n<h2>一、决策前的三个锚点</h2>\\n<p>在做任何技术选型之前，必须先锚定这三件事。锚不住，后面的分析越精细，错的越远。</p>","autoDesc":true}`),a={name:`技术选型方法论.md`};function o(r,i,a,o,s,c){return t(),e(`div`,null,[...i[0]||=[n(`<h1 id="技术选型方法论" tabindex="-1"><a class="header-anchor" href="#技术选型方法论"><span>技术选型方法论</span></a></h1><blockquote><p>技术选型方法论是连接用户需求和技术实现的桥梁，它决定了产品的价值和用户体验。<br> 本文介绍了技术选型方法论的方法论和实践经验，帮助你提升产品思维。</p></blockquote><p>技术选型失败的原因，80%不是技术本身不好，而是<strong>在错误的问题上用了正确的技术</strong>，或者<strong>在错误的时间做了正确的选择</strong>。</p><p>所以方法论的第一步不是教你怎么比较选项，是教你怎么<strong>确保自己在回答正确的问题</strong>。</p><h2 id="一、决策前的三个锚点" tabindex="-1"><a class="header-anchor" href="#一、决策前的三个锚点"><span>一、决策前的三个锚点</span></a></h2><p>在做任何技术选型之前，必须先锚定这三件事。锚不住，后面的分析越精细，错的越远。</p><h3 id="锚点一-你的真实问题是什么" tabindex="-1"><a class="header-anchor" href="#锚点一-你的真实问题是什么"><span>锚点一：你的真实问题是什么？</span></a></h3><p>技术选型最常见的错误不是选错了，而是<strong>选了一件不需要解决的问题的工具</strong>。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>例：团队说&quot;我们需要更好的监控&quot;</span></span>
<span class="line"><span>→ 真实问题可能是：告警太多没人看 → 降噪策略</span></span>
<span class="line"><span>→ 真实问题可能是：故障定位太慢 → 链路追踪</span></span>
<span class="line"><span>→ 真实问题可能是：用户投诉了不知道 → 根因分析SLA</span></span>
<span class="line"><span></span></span>
<span class="line"><span>这三个问题用完全不同的工具解决。</span></span>
<span class="line"><span>如果你直接去买Datadog/Dynatrace，你可能解决了最不重要的那个。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>方法：问题升维</strong></p><p>当你提出一个技术选型需求时，往上问三层：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>第一层：这个技术解决什么问题？</span></span>
<span class="line"><span>  → &quot;更好的监控&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层：这个问题为什么重要？</span></span>
<span class="line"><span>  → &quot;故障时用户受影响&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层：用户真正痛苦的是什么？</span></span>
<span class="line"><span>  → &quot;不知道故障是哪个服务引起的，要排查很久&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层：有没有不靠选型就能解决这个痛苦的方法？</span></span>
<span class="line"><span>  → &quot;加一个值班机制是不是更快？&quot; </span></span>
<span class="line"><span>  → &quot;约定一个日志规范是不是就够了？&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：技术选型是最后的问题解决方案，不是第一个。当你发现不用选型也能解决问题时，节省的成本是100%。</p></blockquote><h3 id="锚点二-你在什么时间窗口里做决策" tabindex="-1"><a class="header-anchor" href="#锚点二-你在什么时间窗口里做决策"><span>锚点二：你在什么时间窗口里做决策？</span></a></h3><p>不同时间的决策质量完全不同。</p><table><thead><tr><th>时间窗口</th><th>决策质量</th><th>策略</th></tr></thead><tbody><tr><td>紧急救火期</td><td>低质量</td><td>先跑通，后优化，接受技术债</td></tr><tr><td>正常规划期</td><td>高质量</td><td>充分评估，可做实验</td></tr><tr><td>回滚窗口期</td><td>关键期</td><td>决定&quot;是否还有机会重来&quot;</td></tr><tr><td>锁定后</td><td>沉默成本</td><td>只能在边缘优化</td></tr></tbody></table><p><strong>方法：决策时效分级</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>如果这个技术要在72小时内上线：</span></span>
<span class="line"><span>  → 不要做全新的技术选型</span></span>
<span class="line"><span>  → 用团队最熟悉的技术</span></span>
<span class="line"><span>  → 接受技术债，打好标记</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果这个技术会在未来3年内持续运行：</span></span>
<span class="line"><span>  → 必须做完整评估</span></span>
<span class="line"><span>  → 评估维度至少包含：团队能力、供应商风险、技术延续性</span></span>
<span class="line"><span>  → 必须有退出策略</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果这个技术会在未来5年内难以更换：</span></span>
<span class="line"><span>  → 这是架构级决策</span></span>
<span class="line"><span>  → 必须有备选方案</span></span>
<span class="line"><span>  → 必须评估锁定成本</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：时间压力越大，越要用熟悉的方案。时间窗口越宽，越值得投入做正确的选择。</p></blockquote><h3 id="锚点三-谁来承担后果" tabindex="-1"><a class="header-anchor" href="#锚点三-谁来承担后果"><span>锚点三：谁来承担后果？</span></a></h3><p>技术选型失败后，谁在承受痛苦？</p><table><thead><tr><th>决策者</th><th>承担者</th><th>后果类型</th></tr></thead><tbody><tr><td>个人开发者</td><td>自己</td><td>时间成本</td></tr><tr><td>小团队负责人</td><td>自己和团队</td><td>时间和团队士气</td></tr><tr><td>技术负责人</td><td>团队和公司</td><td>业务影响和信任</td></tr><tr><td>CTO</td><td>全公司</td><td>战略机会成本</td></tr></tbody></table><p><strong>方法：谁承担，谁参与</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>承担者不是决策者 → 决策质量低，风险高</span></span>
<span class="line"><span>  → 案例：CTO拍板，前端用React，后端用Java，团队是PHP团队</span></span>
<span class="line"><span>  → 结果：花6个月学新技术，业务没推进，还走了两个核心</span></span>
<span class="line"><span></span></span>
<span class="line"><span>承担者是参与者 → 决策质量高，执行力强</span></span>
<span class="line"><span>  → 案例：CTO提出方向，团队一起评估，各自贡献维度</span></span>
<span class="line"><span>  → 结果：决策被团队理解，执行顺畅，遇到问题团队自己解决</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：让承担后果的人参与决策，或者让决策者自己承担后果。</p></blockquote><h2 id="二、评估维度-五维模型" tabindex="-1"><a class="header-anchor" href="#二、评估维度-五维模型"><span>二、评估维度：五维模型</span></a></h2><p>任何技术选型，都从这五个维度评估。不同场景的权重不同，但每个维度必须被回答。</p><h3 id="维度一-适不适合-fit" tabindex="-1"><a class="header-anchor" href="#维度一-适不适合-fit"><span>维度一：适不适合（Fit）</span></a></h3><blockquote><p>这个技术能不能解决你的问题？</p></blockquote><p><strong>必须回答三个子问题</strong>：</p><ol><li><p><strong>问题匹配度</strong>：这个技术设计的核心场景，和你的场景有多接近？</p><ul><li>匹配度 &gt; 80% → 首选</li><li>匹配度 50-80% → 需要定制开发</li><li>匹配度 &lt; 50% → 避免</li></ul></li><li><p><strong>规模适配度</strong>：这个技术设计时考虑的最大规模，和你的规模比如何？</p><ul><li>你用1个MySQL能跑好的，不要上TiDB</li><li>你用Redis能解决的，不要上Kafka</li><li>过早优化和过晚优化一样是错误</li></ul></li><li><p><strong>数据适配度</strong>：你的数据结构，和这个技术擅长处理的数据结构匹配吗？</p><ul><li>关系清晰的 → SQL系</li><li>结构多变的 → Document/NoSQL系</li><li>树形/层级 → 图数据库</li><li>时序 → TSDB</li></ul></li></ol><h3 id="维度二-能不能做-team" tabindex="-1"><a class="header-anchor" href="#维度二-能不能做-team"><span>维度二：能不能做（Team）</span></a></h3><blockquote><p>你的团队能驾驭这个技术吗？</p></blockquote><p><strong>方法：能力评估三问</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>1. 团队里有没有人在生产环境用过这个技术？</span></span>
<span class="line"><span>   有 → 评估他的经验深度</span></span>
<span class="line"><span>   没有 → 需要额外的学习成本和踩坑成本</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 如果这个人走了，能找到替代者吗？</span></span>
<span class="line"><span>   能 → 风险可控</span></span>
<span class="line"><span>   不能 → 这是单点风险，需要降低依赖</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 团队学这个技术需要多久？</span></span>
<span class="line"><span>   &lt; 1周 → 可接受</span></span>
<span class="line"><span>   1-4周 → 需要规划学习投入</span></span>
<span class="line"><span>   &gt; 1个月 → 需要问：这个技术好到值得团队花1个月学吗？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：技术选型评估的不是技术本身有多好，而是你的团队能不能用好它。再好的技术，团队驾驭不了 = 零。</p></blockquote><h3 id="维度三-会不会消失-durability" tabindex="-1"><a class="header-anchor" href="#维度三-会不会消失-durability"><span>维度三：会不会消失（Durability）</span></a></h3><blockquote><p>这个技术明年还在吗？</p></blockquote><p><strong>评估层次</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>第一层：供应商稳定性</span></span>
<span class="line"><span>  → 公司背书：Google/Microsoft/Meta → 风险低；个人项目 → 高风险</span></span>
<span class="line"><span>  → 财务状况：上市公司 → 风险低；VC烧钱 → 看融资轮次</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层：社区活跃度</span></span>
<span class="line"><span>  → GitHub Star是虚的，看：Issue回复速度 / PR合并频率 / 最近更新时间</span></span>
<span class="line"><span>  → 活跃的指标：月均Commit &gt; 10 / Issue平均3天内回复</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层：技术路线图</span></span>
<span class="line"><span>  → 看Changelog：最近半年是否有实质更新</span></span>
<span class="line"><span>  → 看Roadmap：未来6个月规划是否清晰</span></span>
<span class="line"><span>  → 看废弃公告：是否有破坏性变更在计划中</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层：替代技术威胁</span></span>
<span class="line"><span>  → 有没有同赛道更好的技术在崛起？</span></span>
<span class="line"><span>  → 这个技术有没有明显的天花板？</span></span>
<span class="line"><span>  → 3年后这个技术大概在什么位置？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：技术寿命 = 技术本身的寿命 × 供应商的寿命。评估时至少看两层。</p></blockquote><h3 id="维度四-锁定的代价有多高-lock-in" tabindex="-1"><a class="header-anchor" href="#维度四-锁定的代价有多高-lock-in"><span>维度四：锁定的代价有多高（Lock-in）</span></a></h3><blockquote><p>如果选错了，损失有多大？迁移有多难？</p></blockquote><p><strong>锁定类型分级</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>轻锁定（可以低成本迁移）：</span></span>
<span class="line"><span>  → 代码层面的依赖（换个库，改几十行）</span></span>
<span class="line"><span>  → 配置格式的迁移（换个中间件，改配置）</span></span>
<span class="line"><span>  → 工具链的切换（换个IDE，换个构建工具）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中锁定（迁移需要一定成本）：</span></span>
<span class="line"><span>  → 数据格式锁定（用了某种数据库格式，导出困难）</span></span>
<span class="line"><span>  → API锁定（所有调用都通过特定SDK）</span></span>
<span class="line"><span>  → 知识锁定（只有一个人懂这个技术）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>重锁定（几乎无法迁移）：</span></span>
<span class="line"><span>  → 架构锁定（核心业务逻辑和某技术深度绑定）</span></span>
<span class="line"><span>  → 数据锁定（数据量和格式导致无法迁移）</span></span>
<span class="line"><span>  → 团队锁定（整个技术栈围绕某技术构建）</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>方法：锁定成本计算</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>锁定成本 = 迁移所需时间 × 团队月薪 × 迁移期间的机会成本</span></span>
<span class="line"><span></span></span>
<span class="line"><span>举例：</span></span>
<span class="line"><span>  从MySQL迁移到PostgreSQL：1个后端 × 3周 = 约¥5万</span></span>
<span class="line"><span>  从单体迁移到微服务：2人 × 3个月 = 约¥30万</span></span>
<span class="line"><span>  从私有化部署迁移到SaaS：涉及合规整改 = 不可估算</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果锁定成本 &gt; 技术选型节省的成本，选型就是亏的。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：选型时必须同时计算迁移成本。越难迁移的技术，越需要谨慎。</p></blockquote><h3 id="维度五-真实成本是多少-total-cost" tabindex="-1"><a class="header-anchor" href="#维度五-真实成本是多少-total-cost"><span>维度五：真实成本是多少（Total Cost）</span></a></h3><blockquote><p>投入的不只是买软件的钱。</p></blockquote><p><strong>成本分解</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>直接成本（看得见的）：</span></span>
<span class="line"><span>  → 软件授权 / 订阅费用</span></span>
<span class="line"><span>  → 硬件采购 / 云资源费用</span></span>
<span class="line"><span>  → 实施服务费 / 培训费</span></span>
<span class="line"><span></span></span>
<span class="line"><span>间接成本（容易被忽略的）：</span></span>
<span class="line"><span>  → 学习曲线成本：每人每周学习 × 人数 × 周数 × 日薪</span></span>
<span class="line"><span>  → 踩坑成本：新技术的问题排查时间 × 人数 × 时长</span></span>
<span class="line"><span>  → 招聘成本：稀缺技术的薪资溢价 × 招聘周期</span></span>
<span class="line"><span>  → 机会成本：学习新技术占用研发时间</span></span>
<span class="line"><span>  → 运维成本：新技术的监控/备份/恢复/升级</span></span>
<span class="line"><span></span></span>
<span class="line"><span>隐性成本（最后才会暴露的）：</span></span>
<span class="line"><span>  → 技术债累积（为了赶进度欠下的架构债）</span></span>
<span class="line"><span>  → 团队士气损耗（用了烂技术，大家心里都知道）</span></span>
<span class="line"><span>  → 合规风险（新技术的许可证风险、安全漏洞）</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>方法：三年TCO估算</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>TCO = 直接成本 + 间接成本（第一年×1.5）+ 隐性成本（估算）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>举例：选型一个监控系统</span></span>
<span class="line"><span>  直接成本：¥20万（软件+硬件）</span></span>
<span class="line"><span>  间接成本：¥15万（2人学习4周 + 踩坑2周）</span></span>
<span class="line"><span>  隐性成本：¥10万（招聘溢价 + 合规咨询）</span></span>
<span class="line"><span>  三年TCO ≈ ¥75万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对比选型另一个系统：</span></span>
<span class="line"><span>  直接成本：¥5万</span></span>
<span class="line"><span>  间接成本：¥5万（熟悉这个技术）</span></span>
<span class="line"><span>  隐性成本：¥2万</span></span>
<span class="line"><span>  三年TCO ≈ ¥27万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结论：贵的不是买的那一刻，是拥有的整个生命周期。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：三年TCO才是一个技术选型的真实成本报价。只看采购价是商业中最常见的愚蠢行为。</p></blockquote><h2 id="三、决策框架-四步决策法" tabindex="-1"><a class="header-anchor" href="#三、决策框架-四步决策法"><span>三、决策框架：四步决策法</span></a></h2><h3 id="第一步-明确约束条件-constraints" tabindex="-1"><a class="header-anchor" href="#第一步-明确约束条件-constraints"><span>第一步：明确约束条件（Constraints）</span></a></h3><p>在讨论任何选项之前，先把约束写死。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>技术约束：</span></span>
<span class="line"><span>  → 必须兼容现有的浏览器版本</span></span>
<span class="line"><span>  → 必须支持现有的数据库</span></span>
<span class="line"><span>  → 必须在现有服务器上运行</span></span>
<span class="line"><span>  → 必须在2026年内完成迁移</span></span>
<span class="line"><span></span></span>
<span class="line"><span>资源约束：</span></span>
<span class="line"><span>  → 预算上限是多少</span></span>
<span class="line"><span>  → 人员上限是多少</span></span>
<span class="line"><span>  → 时间上限是多少</span></span>
<span class="line"><span></span></span>
<span class="line"><span>合规约束：</span></span>
<span class="line"><span>  → 必须满足哪些安全认证</span></span>
<span class="line"><span>  → 数据必须满足哪些合规要求</span></span>
<span class="line"><span>  → 哪些技术因为合规不能使用</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>常见错误</strong>：把约束当选项。约束是红线，选项是在红线内的选择。</p></blockquote><h3 id="第二步-识别关键维度-key-dimensions" tabindex="-1"><a class="header-anchor" href="#第二步-识别关键维度-key-dimensions"><span>第二步：识别关键维度（Key Dimensions）</span></a></h3><p>从五维模型中选出最重要的2-3个维度，赋予权重。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>不同场景的权重参考：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>业务系统（稳定性优先）：</span></span>
<span class="line"><span>  适不适合 30% + 能不能做 30% + 会不会消失 25% + 锁定代价 15%</span></span>
<span class="line"><span>  成本权重可以低——稳定压倒一切</span></span>
<span class="line"><span></span></span>
<span class="line"><span>快速验证（速度优先）：</span></span>
<span class="line"><span>  能不能做 50% + 适不适合 30% + 成本 20%</span></span>
<span class="line"><span>  其他维度可以妥协——先跑通再说</span></span>
<span class="line"><span></span></span>
<span class="line"><span>长期平台（架构优先）：</span></span>
<span class="line"><span>  会不会消失 35% + 锁定代价 35% + 适不适合 20% + 能不能做 10%</span></span>
<span class="line"><span>  成本权重极低——长期价值才是关键</span></span>
<span class="line"><span></span></span>
<span class="line"><span>创新探索（实验优先）：</span></span>
<span class="line"><span>  适不适合 40% + 成本 30% + 能不能做 20% + 会不会消失 10%</span></span>
<span class="line"><span>  这是实验，不是生产——快速验证才是目的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="第三步-列出选项-然后消灭选项" tabindex="-1"><a class="header-anchor" href="#第三步-列出选项-然后消灭选项"><span>第三步：列出选项，然后消灭选项</span></a></h3><p><strong>消灭选项的方法</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>方法一：硬条件过滤</span></span>
<span class="line"><span>  → 列出所有候选技术</span></span>
<span class="line"><span>  → 用约束条件一条条过滤</span></span>
<span class="line"><span>  → 剩下2-4个进入评估</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法二：快速原型淘汰</span></span>
<span class="line"><span>  → 用2-4小时，每个技术写一个Hello World</span></span>
<span class="line"><span>  → 感受开发体验和社区文档质量</span></span>
<span class="line"><span>  → 通常能淘汰1-2个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法三：参考同行</span></span>
<span class="line"><span>  → 看同规模同行业的公司用什么</span></span>
<span class="line"><span>  → 问他们踩过什么坑</span></span>
<span class="line"><span>  → 不要只看成功案例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法四：消灭最难搞的那个</span></span>
<span class="line"><span>  → 如果两个技术差不多，选团队最熟悉的</span></span>
<span class="line"><span>  → 不要为了&quot;技术更好&quot;选一个大家都不熟的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：决策质量随选项数量指数下降。4选1比8选1质量高。从一开始就不要给自己太多选项。</p></blockquote><h3 id="第四步-做出选择-并写下决策记录" tabindex="-1"><a class="header-anchor" href="#第四步-做出选择-并写下决策记录"><span>第四步：做出选择，并写下决策记录</span></a></h3><p><strong>必须记录的内容</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>决策记录模板：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>技术选型：[技术名称]</span></span>
<span class="line"><span>选型日期：[YYYY-MM-DD]</span></span>
<span class="line"><span>下次复盘日期：[YYYY-MM-DD]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选择原因：</span></span>
<span class="line"><span>  → [为什么选这个，而不是其他？写3条具体原因]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>放弃原因：</span></span>
<span class="line"><span>  → [为什么放弃备选？写2条]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>约束条件（决策时已知的）：</span></span>
<span class="line"><span>  → [时间/预算/团队/技术约束]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>未解决的疑虑：</span></span>
<span class="line"><span>  → [目前仍然担心的点，以及如何监控]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>触发重新评估的条件：</span></span>
<span class="line"><span>  → [如果出现什么情况，需要重新选型]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>原则</strong>：没有记录下来的决策，等于没有做决策。记录的目的是让未来的自己和团队知道当时的推理逻辑。</p></blockquote><h2 id="四、复盘机制-决策必须被验证" tabindex="-1"><a class="header-anchor" href="#四、复盘机制-决策必须被验证"><span>四、复盘机制：决策必须被验证</span></a></h2><p>技术选型最危险的不是选错，而是选错之后不知道。</p><h3 id="复盘时间表" tabindex="-1"><a class="header-anchor" href="#复盘时间表"><span>复盘时间表</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>选型后2周：快速验证</span></span>
<span class="line"><span>  → 预期效果达到了吗？</span></span>
<span class="line"><span>  → 有没有明显的判断失误？</span></span>
<span class="line"><span>  → 这个时候还有机会低成本调整</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选型后3个月：效果评估</span></span>
<span class="line"><span>  → 和预期相比如何？</span></span>
<span class="line"><span>  → 哪些维度高估了？哪些低估了？</span></span>
<span class="line"><span>  → 需要调整使用方式吗？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选型后1年：全面复盘</span></span>
<span class="line"><span>  → TCO实际是多少？</span></span>
<span class="line"><span>  → 团队能力有提升吗？</span></span>
<span class="line"><span>  → 还需要继续用这个技术吗？</span></span>
<span class="line"><span>  → 是否有更好的选项现在出现了？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="决策失效的信号" tabindex="-1"><a class="header-anchor" href="#决策失效的信号"><span>决策失效的信号</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>信号一：预期没有兑现</span></span>
<span class="line"><span>  → 选型时说&quot;3个月能上线&quot;，实际6个月还没稳定</span></span>
<span class="line"><span>  → 选型时说&quot;团队1周能学会&quot;，实际1个月还在踩坑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>信号二：技术债务快速累积</span></span>
<span class="line"><span>  → 为了绕过某个技术的限制，代码里开始有大量 workaround</span></span>
<span class="line"><span>  → 越来越多的&quot;这里特殊处理一下&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>信号三：社区降温</span></span>
<span class="line"><span>  → Issue没人回了</span></span>
<span class="line"><span>  → 半年没更新了</span></span>
<span class="line"><span>  → 竞品明显更活跃了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>信号四：团队怨声载道</span></span>
<span class="line"><span>  → 大家私下说&quot;这个技术太难用了&quot;</span></span>
<span class="line"><span>  → 招不到人，留不住人</span></span>
<span class="line"><span></span></span>
<span class="line"><span>信号五：业务侧不配合</span></span>
<span class="line"><span>  → 产品不愿意基于这个技术设计功能</span></span>
<span class="line"><span>  → 业务方主动绕开这个技术</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、不同类型选型的特殊规则" tabindex="-1"><a class="header-anchor" href="#五、不同类型选型的特殊规则"><span>五、不同类型选型的特殊规则</span></a></h2><h3 id="语言-框架选型" tabindex="-1"><a class="header-anchor" href="#语言-框架选型"><span>语言/框架选型</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>核心原则：语言和框架是最容易换的，也是最容易被锁定的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>容易换的部分：</span></span>
<span class="line"><span>  → 后端API框架（FastAPI → Express → Spring Boot）</span></span>
<span class="line"><span>  → 前端UI框架（React → Vue → Svelte）</span></span>
<span class="line"><span>  → 脚本语言（Python → Node.js）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不容易换的部分：</span></span>
<span class="line"><span>  → 核心业务逻辑写死的部分</span></span>
<span class="line"><span>  → 团队的知识积累</span></span>
<span class="line"><span>  → 工具链生态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法论：</span></span>
<span class="line"><span>  1. 用最熟悉的语言先跑通业务</span></span>
<span class="line"><span>  2. 把业务逻辑写干净，方便以后迁移</span></span>
<span class="line"><span>  3. 不要为&quot;性能更好&quot;换语言——性能问题通常是算法问题</span></span>
<span class="line"><span>  4. 不要为&quot;工资更高&quot;换语言——技术债是真实的债务</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数据库选型" tabindex="-1"><a class="header-anchor" href="#数据库选型"><span>数据库选型</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>核心原则：数据库是技术栈中迁移成本最高的，选型必须最谨慎</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选型决策树：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你的数据是什么样的？</span></span>
<span class="line"><span>├── 结构固定的 → MySQL / PostgreSQL</span></span>
<span class="line"><span>│   ├── 规模极大 → TiDB / CockroachDB</span></span>
<span class="line"><span>│   └── 规模一般 → MySQL / PostgreSQL（哪个熟悉选哪个）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 结构多变的 → MongoDB / PostgreSQL JSON</span></span>
<span class="line"><span>│   ├── 需要全文检索 → MongoDB + Elasticsearch</span></span>
<span class="line"><span>│   └── 需要事务 → PostgreSQL（强于MongoDB）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 图关系为主的 → Neo4j / NebulaGraph</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 时序数据 → InfluxDB / TimescaleDB</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── 向量数据 → Milvus / Qdrant / ChromaDB</span></span>
<span class="line"><span>    └── 如果向量量 &lt; 100万条 → ChromaDB</span></span>
<span class="line"><span>    └── 如果向量量 &gt; 100万条 → Milvus / Qdrant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法论：</span></span>
<span class="line"><span>  1. 优先选PostgreSQL——它是全才</span></span>
<span class="line"><span>  2. 只有PostgreSQL明确不擅长的场景才选专用数据库</span></span>
<span class="line"><span>  3. 同一个数据不要存两套（MySQL + MongoDB各一份）——这是维护灾难</span></span>
<span class="line"><span>  4. 选型时必须考虑数据迁移工具是否完善</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="云服务商-基础设施选型" tabindex="-1"><a class="header-anchor" href="#云服务商-基础设施选型"><span>云服务商/基础设施选型</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>核心原则：云服务商是锁定成本最高的选型之一</span></span>
<span class="line"><span></span></span>
<span class="line"><span>评估层次：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第一层：核心服务可用性</span></span>
<span class="line"><span>  → 计算/存储/网络的SLA是多少</span></span>
<span class="line"><span>  → 历史上有没有重大宕机</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层：数据迁移难度</span></span>
<span class="line"><span>  → 数据能否低成本导出</span></span>
<span class="line"><span>  → 是否有其他云服务商的迁移工具</span></span>
<span class="line"><span>  → 锁定是技术锁定还是数据锁定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层：成本结构</span></span>
<span class="line"><span>  → 长期使用是否线性增长</span></span>
<span class="line"><span>  → 预留实例是否值得购买</span></span>
<span class="line"><span>  → 出了超预期流量账单怎么办</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层：合规覆盖</span></span>
<span class="line"><span>  → 覆盖了哪些认证（等保/ISO/SOC2）</span></span>
<span class="line"><span>  → 在你需要开展业务的地区是否有节点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法论：</span></span>
<span class="line"><span>  1. 多云策略适合大公司，小公司不要搞多云——运维成本太高</span></span>
<span class="line"><span>  2. 如果数据量不大，可以用云服务商提供的免费额度做实验</span></span>
<span class="line"><span>  3. 永远问：把我的数据迁出去需要多久？</span></span>
<span class="line"><span>  4. 成本估算要包括&quot;促销结束后&quot;的价格</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="硬件采购选型" tabindex="-1"><a class="header-anchor" href="#硬件采购选型"><span>硬件采购选型</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>核心原则：硬件是所有选型中沉没成本最高的，选错就是真金白银的损失</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法一：先云后硬</span></span>
<span class="line"><span>  → 任何新工作负载，先在云上跑3-6个月</span></span>
<span class="line"><span>  → 摸清真实用量和性能需求后，再决定是否采购硬件</span></span>
<span class="line"><span>  → 云上的峰值用量 × 6个月 = 采购的最低配置参考</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法二：按需配置，而非一步到位</span></span>
<span class="line"><span>  → CPU：按实际峰值CPU的150%配置</span></span>
<span class="line"><span>  → 内存：按实际使用量的120%配置</span></span>
<span class="line"><span>  → 存储：预估未来1年的数据增长 + 30%冗余</span></span>
<span class="line"><span>  → GPU：按单卡显存够用选择，不要买超过需求的卡</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法三：采购决策树</span></span>
<span class="line"><span>  ├── 使用频率 &lt; 30% → 租/云</span></span>
<span class="line"><span>  ├── 使用频率 &gt; 70%，且用量稳定 → 采购</span></span>
<span class="line"><span>  ├── 使用频率 &gt; 70%，但用量波动大 → 预留实例/混合</span></span>
<span class="line"><span>  └── 不确定 → 继续用云，6个月后再评估</span></span>
<span class="line"><span></span></span>
<span class="line"><span>硬件选型常见错误：</span></span>
<span class="line"><span>  ❌ 按最高配置买，想着&quot;以后肯定用得上&quot;</span></span>
<span class="line"><span>  ❌ 忽略运维成本（电费、空调、UPS、机柜）</span></span>
<span class="line"><span>  ❌ 只看采购价，忽略生命周期总成本</span></span>
<span class="line"><span>  ❌ 为省钱买二手/矿卡（稳定性风险极高）</span></span>
<span class="line"><span>  ❌ 不留扩展余量（业务增长后被迫提前换机器）</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="供应商-saas选型" tabindex="-1"><a class="header-anchor" href="#供应商-saas选型"><span>供应商/SaaS选型</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>核心原则：供应商选型不只是评估功能，是评估这家公司能陪你走多久</span></span>
<span class="line"><span></span></span>
<span class="line"><span>评估层次：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第一层：产品力</span></span>
<span class="line"><span>  → 功能是否满足需求</span></span>
<span class="line"><span>  → 体验是否流畅</span></span>
<span class="line"><span>  → 是否有明显短板</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层：公司力</span></span>
<span class="line"><span>  → 公司成立多久了</span></span>
<span class="line"><span>  → 融资轮次和烧钱速度</span></span>
<span class="line"><span>  → 创始团队背景</span></span>
<span class="line"><span>  → 核心员工流失率</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层：安全合规</span></span>
<span class="line"><span>  → 有哪些安全认证</span></span>
<span class="line"><span>  → 数据如何隔离</span></span>
<span class="line"><span>  → 是否有合规问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层：退出成本</span></span>
<span class="line"><span>  → 数据能否导出（格式是什么）</span></span>
<span class="line"><span>  → 导出需要多久</span></span>
<span class="line"><span>  → 有没有锁定陷阱（数据格式私有化）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>红线（遇到任何一个就换掉）：</span></span>
<span class="line"><span>  ❌ 无法导出全部数据</span></span>
<span class="line"><span>  ❌ 价格随意涨，没有合同保障</span></span>
<span class="line"><span>  ❌ 服务商明显在走下坡路</span></span>
<span class="line"><span>  ❌ 核心功能开始停滞开发</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="六、组织级选型-大公司的特殊规则" tabindex="-1"><a class="header-anchor" href="#六、组织级选型-大公司的特殊规则"><span>六、组织级选型：大公司的特殊规则</span></a></h2><h3 id="当选型变成政治问题" tabindex="-1"><a class="header-anchor" href="#当选型变成政治问题"><span>当选型变成政治问题</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 架构师推荐A，技术负责人坚持B，谁都说不服不了谁</span></span>
<span class="line"><span>  → 最终由CTO拍板，但两个方案都没被充分评估</span></span>
<span class="line"><span>  → 选了一个&quot;大家都能接受&quot;的折中方案，其实是四不像</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法——决策权分层：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>架构级决策（跨团队影响 &gt; 6个月）：</span></span>
<span class="line"><span>  → 决策权：CTO/技术VP</span></span>
<span class="line"><span>  → 流程：技术委员会评审，各方陈述，CTO决定</span></span>
<span class="line"><span>  → 原则：听多数人的意见，参考少数人的建议，一个人做决定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>团队级决策（影响本团队 &lt; 6个月）：</span></span>
<span class="line"><span>  → 决策权：技术负责人</span></span>
<span class="line"><span>  → 流程：团队内部评估，技术负责人决定</span></span>
<span class="line"><span>  → 原则：谁承担后果谁做决定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>个人级决策（影响自己 &lt; 1周）：</span></span>
<span class="line"><span>  → 决策权：个人</span></span>
<span class="line"><span>  → 流程：不用评审，自己决定</span></span>
<span class="line"><span>  → 原则：可以先斩后奏，但需要事后同步</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="当选型遇到派系斗争" tabindex="-1"><a class="header-anchor" href="#当选型遇到派系斗争"><span>当选型遇到派系斗争</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>方法一：数据说话</span></span>
<span class="line"><span>  → 不要争论&quot;哪个更好&quot;，争论&quot;哪个指标更能反映我们的需求&quot;</span></span>
<span class="line"><span>  → 用一个共同认可的评估框架，让数据替你说服人</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法二：实验验证</span></span>
<span class="line"><span>  → 两个方案各跑一个月，用实际数据说话</span></span>
<span class="line"><span>  → 这是技术选型中最公平的方式</span></span>
<span class="line"><span>  → 但需要有明确的评估指标（延迟/TCO/团队满意度）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法三：升维</span></span>
<span class="line"><span>  → 把争论从&quot;哪个技术更好&quot;升到&quot;我们公司的技术战略是什么&quot;</span></span>
<span class="line"><span>  → 战略一致了，具体选型自然清晰</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方法四：让更高层做不受欢迎的决定</span></span>
<span class="line"><span>  → 有些决定必须有人承担政治压力</span></span>
<span class="line"><span>  → 这不是逃避，是责任分层</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="七、常见错误与避坑指南" tabindex="-1"><a class="header-anchor" href="#七、常见错误与避坑指南"><span>七、常见错误与避坑指南</span></a></h2><h3 id="错误一-简历驱动开发-resume-driven-development" tabindex="-1"><a class="header-anchor" href="#错误一-简历驱动开发-resume-driven-development"><span>错误一：简历驱动开发（Resume-Driven Development）</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → &quot;我们要用Rust，因为Rust很火&quot;</span></span>
<span class="line"><span>  → &quot;用Go比较好，Go是Google的&quot;</span></span>
<span class="line"><span>  → &quot;这个技术是大厂在用的，我们也要用&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本质：用技术给简历镀金，而不是用技术解决业务问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：问这个问题</span></span>
<span class="line"><span>  → &quot;如果这个技术在简历上毫无价值，你还选它吗？&quot;</span></span>
<span class="line"><span>  → 如果答案是&quot;不&quot;，说明这不是正确的选型理由</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="错误二-上一个项目的问题还没解决-又引入新技术" tabindex="-1"><a class="header-anchor" href="#错误二-上一个项目的问题还没解决-又引入新技术"><span>错误二：上一个项目的问题还没解决，又引入新技术</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 技术债还没还完，又引入新框架</span></span>
<span class="line"><span>  → 三套系统在并行跑，每套都是半吊子</span></span>
<span class="line"><span>  → &quot;这个新技术可以解决老系统的问题&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本质：用新问题来解决旧问题，是问题倍增器</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：</span></span>
<span class="line"><span>  → 先把现有的技术债还到一个可接受的程度</span></span>
<span class="line"><span>  → 再引入新技术</span></span>
<span class="line"><span>  → 问自己：老系统的核心问题，是因为技术不行，还是因为写代码的人不行？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="错误三-把-免费-当-便宜" tabindex="-1"><a class="header-anchor" href="#错误三-把-免费-当-便宜"><span>错误三：把&quot;免费&quot;当&quot;便宜&quot;</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 选开源软件——免费</span></span>
<span class="line"><span>  → 选云服务商的免费额度——免费</span></span>
<span class="line"><span>  → 选个人开发者的开源项目——免费</span></span>
<span class="line"><span></span></span>
<span class="line"><span>真相：</span></span>
<span class="line"><span>  → 开源软件：采购免费，运维有成本，学习有成本，踩坑有成本</span></span>
<span class="line"><span>  → 免费云额度：超过额度后按量付费通常比预付贵3-5倍</span></span>
<span class="line"><span>  → 个人开源项目：随时可能停止维护</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：</span></span>
<span class="line"><span>  → &quot;免费&quot;只算进了采购成本，TCO里还有其他项</span></span>
<span class="line"><span>  → 问：这个&quot;免费&quot;的东西，配套的文档、培训、出了问题有人管吗？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="错误四-过度设计-over-engineering" tabindex="-1"><a class="header-anchor" href="#错误四-过度设计-over-engineering"><span>错误四：过度设计（Over-engineering）</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 5个人的团队，要搞微服务</span></span>
<span class="line"><span>  → 月活1万的系统，要上Kafka</span></span>
<span class="line"><span>  → 两个人开发，要上完整的CI/CD和自动化测试</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本质：用复杂的技术解决简单的问题，是杀鸡用牛刀的反面</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：</span></span>
<span class="line"><span>  → 技术复杂度应该和业务复杂度匹配</span></span>
<span class="line"><span>  → 问问自己：如果把这个技术拿掉，核心问题解决不了吗？</span></span>
<span class="line"><span>  → 先把简单的方案做到极致，再考虑复杂化</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="错误五-锚定效应-anchoring" tabindex="-1"><a class="header-anchor" href="#错误五-锚定效应-anchoring"><span>错误五：锚定效应（Anchoring）</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 第一个听到的技术名字，往往成为最终选择</span></span>
<span class="line"><span>  → &quot;我已经想好了用React，别的我都不看&quot;</span></span>
<span class="line"><span>  → 先调研后选型变成了&quot;为已有结论找理由&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本质：决策不是基于分析，而是基于顺序</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：</span></span>
<span class="line"><span>  → 先定义评估维度，再列选项</span></span>
<span class="line"><span>  → 强迫自己给每个选项的每个维度打分</span></span>
<span class="line"><span>  → 问：这个技术如果是你最后才想到的，你还会选它吗？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="错误六-群体思维-groupthink" tabindex="-1"><a class="header-anchor" href="#错误六-群体思维-groupthink"><span>错误六：群体思维（Groupthink）</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>症状：</span></span>
<span class="line"><span>  → 讨论选型时，没有人提出反对意见</span></span>
<span class="line"><span>  → 大家都&quot;同意&quot;这个选型</span></span>
<span class="line"><span>  → 但实际上每个人心里都有疑虑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本质：共识掩盖了真实的分歧</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解法：</span></span>
<span class="line"><span>  → 明确要求&quot;反对意见&quot;</span></span>
<span class="line"><span>  → 设立&quot;红队&quot;角色，专门负责质疑</span></span>
<span class="line"><span>  → 最终决策可以服从多数，但必须先听到反对</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="八、总结-技术选型的底层逻辑" tabindex="-1"><a class="header-anchor" href="#八、总结-技术选型的底层逻辑"><span>八、总结：技术选型的底层逻辑</span></a></h2><h3 id="一句话原则" tabindex="-1"><a class="header-anchor" href="#一句话原则"><span>一句话原则</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>不是什么：</span></span>
<span class="line"><span>  ❌ 不是选最强的技术</span></span>
<span class="line"><span>  ❌ 不是选最便宜的技术</span></span>
<span class="line"><span>  ❌ 不是选最流行的技术</span></span>
<span class="line"><span>  ❌ 不是选个人喜好的技术</span></span>
<span class="line"><span></span></span>
<span class="line"><span>是什么：</span></span>
<span class="line"><span>  ✅ 是选那个在约束条件下，能让承担后果的人睡得着觉的技术</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="选型质量的三个检验" tabindex="-1"><a class="header-anchor" href="#选型质量的三个检验"><span>选型质量的三个检验</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-"><span class="line"><span>检验一：六个月检验</span></span>
<span class="line"><span>  → 六个月后，这个选型带来的价值是否明显大于成本？</span></span>
<span class="line"><span>  → 如果不确定，重写你的评估报告</span></span>
<span class="line"><span></span></span>
<span class="line"><span>检验二：换人检验</span></span>
<span class="line"><span>  → 如果核心技术负责人明天离职，这个技术还能继续用吗？</span></span>
<span class="line"><span>  → 如果不能，这个选型是依赖个人的，是脆弱的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>检验三：竞争对手检验</span></span>
<span class="line"><span>  → 如果竞争对手也在用这个技术，你会更放心还是更担心？</span></span>
<span class="line"><span>  → 如果更担心，说明技术差异化价值不大</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="最后的提醒" tabindex="-1"><a class="header-anchor" href="#最后的提醒"><span>最后的提醒</span></a></h3><blockquote><p>技术选型没有标准答案，只有适不适合。方法论给你的是<strong>思考框架</strong>，不是<strong>决策结果</strong>。<br> 最危险的不是选错了，而是<strong>不知道自己为什么选</strong>。<br> 记录你的决策逻辑，定期复盘，让错误变成组织知识——这才是技术选型方法论的最终目的。</p></blockquote><p><em>方法论的价值在于被使用，不在于被记住。</em></p>`,114)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};